import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

// Example data for complaints (you can replace this with actual data from an API)
const exampleComplaints = [
  { id: 1, title: 'Broken Street Light', status: 'Pending' },
  { id: 2, title: 'Leaking Water Pipe', status: 'In Progress' },
  { id: 3, title: 'Dirty Park', status: 'Resolved' },
];

const Dashboard = () => {
  const [complaints, setComplaints] = useState([]);

  useEffect(() => {
    // Here you would fetch complaints from an API or database
    // For now, we're using the example data
    setComplaints(exampleComplaints);
  }, []);

  return (
    <div className="dashboard-container">
      <h1>Your Complaints</h1>

      <div className="complaints-list">
        {complaints.length > 0 ? (
          complaints.map(complaint => (
            <div key={complaint.id} className="complaint-card">
              <h3>{complaint.title}</h3>
              <p>Status: {complaint.status}</p>
              <Link to={`/complaints/${complaint.id}`} className="view-details">
                View Details
              </Link>
            </div>
          ))
        ) : (
          <p>No complaints found. Please add a new complaint.</p>
        )}
      </div>
    </div>
  );
};

export default Dashboard;
